mapper.select:
select schedule_id, staff_id, week_scope, weekday, time_slot, is_available, available_hours, adjust_reason, notify_staff, operator_id, create_by, create_time, update_by, update_time, remark from osg_staff_schedule
and staff_id = #{staffId}
and week_scope = #{weekScope}
order by staff_id asc, weekday asc, case time_slot when 'morning' then 1 when 'afternoon' then 2 when 'evening' then 3 else 4 end asc

mapper.delete:
delete from osg_staff_schedule
where staff_id = #{staffId}
  and week_scope = #{weekScope}
